sql:
SELECT expenditure
FROM expenditure_data
WHERE region_id = 0 AND year_id = 0;

SELECT SUM(expenditure) AS total_expenditure
  FROM expenditure_data
  WHERE region_id = 0;

external_knowledge:
North America refers to the region with region_id = 0; 
The years of interest are between 2008 and 2010, where 2008 is the start year and 2010 is the end year; 
Top 3 expenditure categories are determined by ranking the categories for each year in descending order of expenditure percentage.

sql:
SELECT DISTINCT category_name
FROM expenditure_categories
ORDER BY category_name;

SELECT region_id, AVG(expenditure) AS average_expenditure
FROM expenditure_data
GROUP BY region_id;

SELECT category_name
FROM expenditure_categories
WHERE category_type = 'consumption';

SELECT SUM(data_value) AS total_data_value
FROM report_data
WHERE report_id = 0;

external_knowledge:
* Average expenditure per capita is a measure of the total expenditure divided by the population, which gives the average amount spent per person; 
* Ranking by average expenditure per capita in descending order means arranging the regions from the highest to lowest average expenditure per person;
* The year 2009-2010 is a specific financial year of interest.

sql:
SELECT region_name 
FROM regions 
ORDER BY region_name;

SELECT report_id
FROM reports
WHERE title = 'Expenditure Trends 2009-2010';

SELECT DISTINCT r.region_name
FROM expenditure_data ed
JOIN regions r ON ed.region_id = r.region_id;

SELECT MAX(expenditure) AS max_expenditure
FROM expenditure_data
WHERE category_id = 1 AND year_id = (SELECT year_id FROM years WHERE year_name = '2022');

SELECT MAX(expenditure) AS max_expenditure
FROM expenditure_data
WHERE category_id = 1 AND year_id = 0;
